mapper.select:
SELECT m.memberNo, m.memberId, m.memberStatus, m.role, mi.etc FROM member m join memberInfo mi on m.memberNo = mi.memberNo
role = 'ROLE_USER'
AND memberId = #{memberId}
AND memberStatus = #{memberStatus}

mapper.update:
	 UPDATE member
    SET memberStatus = #{memberStatus}
    WHERE memberNo = #{memberNo}

	 UPDATE memberInfo
     SET etc = #{etc}
     WHERE memberNo = #{memberNo}
